function wadMul(uint256 a, uint256 b) internal pure returns (uint256 c) {
  // to avoid overflow, a <= (type(uint256).max - HALF_WAD) / b
  assembly {
    if iszero(or(iszero(b), iszero(gt(a, div(sub(not(0), HALF_WAD), b))))) {
      revert(0, 0)
    }

    c := div(add(mul(a, b), HALF_WAD), WAD)
  }
}

function rayMul(uint256 a, uint256 b) internal pure returns (uint256 c) {
  // to avoid overflow, a <= (type(uint256).max - HALF_RAY) / b
  assembly {
    if iszero(or(iszero(b), iszero(gt(a, div(sub(not(0), HALF_RAY), b))))) {
      revert(0, 0)
    }

    c := div(add(mul(a, b), HALF_RAY), RAY)
  }
}

function rayDiv(uint256 a, uint256 b) internal pure returns (uint256 c) {
  // to avoid overflow, a <= (type(uint256).max - halfB) / RAY
  assembly {
    if or(iszero(b), iszero(iszero(gt(a, div(sub(not(0), div(b, 2)), RAY))))) {
      revert(0, 0)
    }

    c := div(add(mul(a, RAY), div(b, 2)), b)
  }
}

function powu(UD60x18 x, uint256 y) pure returns (UD60x18 result) {
    // Calculate the first iteration of the loop in advance.
    uint256 xUint = x.unwrap();
    uint256 resultUint = y & 1 > 0 ? xUint : uUNIT;

    // Equivalent to `for(y /= 2; y > 0; y /= 2)`.
    for (y >>= 1; y > 0; y >>= 1) {
        xUint = Common.mulDiv18(xUint, xUint);

        // Equivalent to `y % 2 == 1`.
        if (y & 1 > 0) {
            resultUint = Common.mulDiv18(resultUint, xUint);
        }
    }
    result = wrap(resultUint);
}

function exp(UD60x18 x) pure returns (UD60x18 result) {
    uint256 xUint = x.unwrap();

    // This check prevents values greater than 192e18 from being passed to {exp2}.
    if (xUint > uEXP_MAX_INPUT) {
        revert Errors.PRBMath_UD60x18_Exp_InputTooBig(x);
    }

    unchecked {
        // Inline the fixed-point multiplication to save gas.
        uint256 doubleUnitProduct = xUint * uLOG2_E;
        result = exp2(wrap(doubleUnitProduct / uUNIT));
    }
}

function sqrt(UD60x18 x) pure returns (UD60x18 result) {
    uint256 xUint = x.unwrap();

    unchecked {
        if (xUint > uMAX_UD60x18 / uUNIT) {
            revert Errors.PRBMath_UD60x18_Sqrt_Overflow(x);
        }
        // Multiply x by `UNIT` to account for the factor of `UNIT` picked up when multiplying two UD60x18 numbers.
        // In this case, the two numbers are both the square root.
        result = wrap(Common.sqrt(xUint * uUNIT));
    }
}

function highestBitSet(uint self) internal pure returns (uint8 highest) {
    require(self != 0);
    uint val = self;
    for (uint8 i = 128; i >= 1; i >>= 1) {
        if (val & (ONE << i) - 1 << i != 0) {
            highest += i;
            val >>= i;
        }
    }
}

function supportsInterface(bytes4 interfaceId) public view virtual override(ERC165, IERC165) returns (bool) {
    return
        interfaceId == type(IERC721).interfaceId ||
        interfaceId == type(IERC721Timestamped).interfaceId ||
        interfaceId == type(IERC721Burnable).interfaceId ||
        interfaceId == type(IERC721MetaTx).interfaceId ||
        interfaceId == type(IERC721Metadata).interfaceId ||
        super.supportsInterface(interfaceId);
}

function getTermsInfo(bytes calldata _terms) public pure returns (bytes4[] memory allowedMethods_) {
    uint256 j = 0;
    uint256 termsLength_ = _terms.length;
    require(termsLength_ % 4 == 0 && termsLength_ != 0, "AllowedMethodsEnforcer:invalid-terms-length");
    allowedMethods_ = new bytes4[](termsLength_ / 4);
    for (uint256 i = 0; i < termsLength_; i += 4) {
        allowedMethods_[j] = bytes4(_terms[i:i + 4]);
        j++;
    }
}

function liquidateAccount(uint256 tokenId) public override onlyTreasury {

    uint256 accountLevel = accountLevels[tokenId];
    string[] memory URLs = new string[](accountLevel + 1);
    for(uint256 x = 0; x < URLs.length; x++) {
        URLs[x] = levelSettings[x].unstakedURL;
    }

    IUnstakedNFTMinter(contractRegistry.getContractAddress(UNSTAKED_NFTS_HASH)).mintUnstakedTokens(ownerOf(tokenId), URLs);

    _burn(tokenId);
}

function intoUint40(SD21x18 x) pure returns (uint40 result) {
    int128 xInt = SD21x18.unwrap(x);
    if (xInt < 0) {
        revert CastingErrors.PRBMath_SD21x18_ToUint40_Underflow(x);
    }
    if (xInt > int128(uint128(Common.MAX_UINT40))) {
        revert CastingErrors.PRBMath_SD21x18_ToUint40_Overflow(x);
    }
    result = uint40(uint128(xInt));
}

function intoSD1x18(UD60x18 x) pure returns (SD1x18 result) {
    uint256 xUint = UD60x18.unwrap(x);
    if (xUint > uint256(int256(uMAX_SD1x18))) {
        revert CastingErrors.PRBMath_UD60x18_IntoSD1x18_Overflow(x);
    }
    result = SD1x18.wrap(int64(uint64(xUint)));
}

function setHoldingPosition(uint32 positionId) public {
    _isAuthorized();
    if (!isPositionUsed[positionId]) revert Cellar__PositionNotUsed(positionId);
    if (_assetOf(positionId) != asset) revert Cellar__AssetMismatch(address(asset), address(_assetOf(positionId)));
    if (getPositionData[positionId].isDebt) revert Cellar__InvalidHoldingPosition(positionId);
    holdingPosition = positionId;
}

function delegateBySig(address delegatee, uint256 nonce, uint256 expiry, uint8 v, bytes32 r, bytes32 s) public {
    require(block.timestamp <= expiry, "ERC20Votes: signature expired");
    address signer = ECDSA.recover(
        _hashTypedDataV4(keccak256(abi.encode(_DELEGATION_TYPEHASH, delegatee, nonce, expiry))),
        v,
        r,
        s
    );
    require(nonce == _useNonce(signer), "ERC20Votes: invalid nonce");
    _delegate(signer, delegatee);
}

function safeDiv(uint256 a, uint256 b) internal pure returns (uint256) {
    if (b == 0) {
        LibRichErrors.rrevert(
            LibSafeMathRichErrors.Uint256BinOpError(LibSafeMathRichErrors.BinOpErrorCodes.DIVISION_BY_ZERO, a, b)
        );
    }
    uint256 c = a / b;
    return c;
}

function safeSub(uint256 a, uint256 b) internal pure returns (uint256) {
    if (b > a) {
        LibRichErrors.rrevert(
            LibSafeMathRichErrors.Uint256BinOpError(
                LibSafeMathRichErrors.BinOpErrorCodes.SUBTRACTION_UNDERFLOW,
                a,
                b
            )
        );
    }
    return a - b;
}

function safeAdd(uint256 a, uint256 b) internal pure returns (uint256) {
    uint256 c = a + b;
    if (c < a) {
        LibRichErrors.rrevert(
            LibSafeMathRichErrors.Uint256BinOpError(LibSafeMathRichErrors.BinOpErrorCodes.ADDITION_OVERFLOW, a, b)
        );
    }
    return c;
}

function safeDiv(uint256 a, uint256 b) internal pure returns (uint256) {
